def day_7_solver(file):
    with open(file) as input:
        instructions = [line.strip() for line in input]

    # Rearrange equation.
    for i, line in enumerate(instructions):
        exp, var = line.split(' -> ')
        instructions[i] = '{} = {}'.format(var, exp)

    # Sort by wire for major speed improvement.
    instructions.sort(key=lambda wire: (len(wire.split()[0]), wire.split()[0]))

    # Replace operators and 2 letter keyword variable names.
    dict = {'NOT':'~', 'AND':'&', 'OR':'|', 'LSHIFT':'<<', 'RSHIFT':'>>',
            'as':'_as', 'if':'_if', 'or':'_or', 'in':'_in', 'is':'_is'}
    for i,_ in enumerate(instructions):
        for key, val in dict.items():
            instructions[i] = instructions[i].replace(key, val)

    # Track completed lines and finished wires.
    completed = set()
    wires = {}

    # Attempt to exec each line over and over until something works.
    while len(completed) != len(instructions):
        for line in instructions:
            try:
                exec(line, {}, wires)
                completed.add(line)
            except NameError:
                pass

    return 'wire a = {}'.format(wires['a'])

if __name__ == "__main__":
    main()

import scala.annotation.tailrec
import scala.io.Source

object Day8 {

  def countRepresentedChars(s: String): Int = {
    @tailrec
    def go(counted: Int, remaining: Seq[Char]): Int = {
      if (remaining.isEmpty) counted
      else remaining match {
        case Seq('"', rest@_*) => go(counted, rest) // ignore surrounding quotes
        case Seq('\\', 'x', _, _, rest@_*) => go(counted + 1, rest) // match \x..
        case Seq('\\', _, rest@_*) => go(counted + 1, rest) // match \" and \\
        case Seq(_, rest@_*) => go(counted + 1, rest) // match single character
      }
    }
    go(0, s.trim.toSeq)
  }

  def countEncodedChars(s: String): Int = {
    s.replace( """\""", """\\""").replace( """"""", """\"""").length + 2
  }

  def calcDifference(lines: Seq[String], f: String => Int): Int = {
    val representedChars = lines.map(f)
    val codeChars = lines.map(_.length)
    codeChars.sum - representedChars.sum
  }

  def main(args: Array[String]) = {
    val lines = Source.fromFile("input-day8.txt").getLines().toSeq
    // part 1
    println(calcDifference(lines, countRepresentedChars))
    // part 2
    println(-calcDifference(lines, countEncodedChars))
  }

}

