def validTriangle(line):
	line = sorted(list(map(lambda x: int(x), line)))
	return ((line[0] + line[1]) > line[2])

def validTriangeCount(rows):
	triangleCount = 0
	for row in zip(*rows):
		triangleCount += validTriangle(row)
	return triangleCount

def part1():
	triangleCount = 0
	with open('input.txt', 'r') as file:
