    ret = []
    for spot in cur:
        x, y = (i for i in spot)
        if x != 0:
            if (x - 1, y) not in vis and clear(x - 1, y):
                vis.add(tuple([x - 1, y]))
                ret.append(tuple([x - 1, y]))
        if y != 0:
            if (x, y - 1) not in vis and clear(x, y - 1):
                vis.add(tuple([x, y - 1]))
                ret.append(tuple([x, y - 1]))
        if (x + 1, y) not in vis and clear(x + 1, y):
            vis.add(tuple([x + 1, y]))
            ret.append(tuple([x + 1, y]))
        if (x, y + 1) not in vis and clear(x, y + 1):
            vis.add(tuple([x, y + 1]))
            ret.append(tuple([x, y + 1]))
    return ret


