def compare(reg_val, comp, comp_val):
    comp_val = int(comp_val)
    if comp == "!=":
        return not reg_val == comp_val
    elif comp == ">=":
        return reg_val >= comp_val
    elif comp == ">":
        return reg_val > comp_val
    elif comp == "<=":
        return reg_val <= comp_val
    elif comp == "<":
        return reg_val < comp_val
    return reg_val == comp_val

