from cmath import exp, pi
from sys import argv

def angle(n):
    return exp(2*pi*n/6j)

nms = ["n", "ne", "se", "s", "sw", "nw"]

delta = {
  "n": angle(0),
  "ne": angle(1),
  "se": angle(2),
  "s": angle(3),
  "sw": angle(4),
  "nw": angle(5),
}

def location(steps):
    loc= 0
    for s in steps:
        loc+= delta[s]
    return loc

def furthest(steps):
    loc= 0
    dist= 0
    for s in steps:
        loc+= delta[s]
        if abs(loc) > abs(dist):
            dist= loc
    return dist

def path(loc):
    p= []
    while 0.01<abs(loc):
        probe= [abs(loc-delta[s]) for s in nms]
        s= nms[probe.index(min(probe))]
        loc-= delta[s]
        p.append(s)
    return p

def showpath(loc):
    p= path(loc)
    print("steps: %d" % len(p))
    d= [0,0,0,0,0,0]
    for s in p:
        d[nms.index(s)]+= 1
    for s in nms:
        if 0<d[nms.index(s)]:
            print("%d %s" % (d[nms.index(s)],s))

