        elif state=="F":
            mov=(-mov[0],-mov[1])
        x+=mov[0]
        y+=mov[1]
        if x < 0:
            x+=1
            grid.insert(0, ["."]*len(grid[0]))
        elif x == len(grid):
            grid.append(["."]*len(grid[0]))
        if y < 0:
            y+=1
            for row in grid:
                row.insert(0,".")
        elif y == len(grid[0]):
            for row in grid:
                row.append(".")
    return infections

