def polymer_length(p):
    p1 = 0
    p2 = 1

    while p2 < len(p):
        if p[p1].swapcase() == p[p2]:
            p = p[:p1] + p[p2+1:]
            # indices will change (i.e. characters wisll move "back")
            if p1 >= 1:
                p1 -= 1
            else:
                p1 = 0
            p2 = p1 + 1
        else:
            p1 += 1
            p2 += 1

    return len(p)

