import time

input_filename = "../input/input_day8.txt"

class Node:
    def __init__(self, ind, child_remainging, data_len):
        self.ind = ind
        self.child_remaining = child_remainging
        self.data_len = data_len
        self.children = []
        self.data_vals = []

    def __repr__(self):
        return f"Node(ind: {self.ind}, metadata items:{self.data_len}, children:{len(self.children)})"

    def metadata_sum(self):
        return sum(self.data_vals) + sum(child.metadata_sum() for child in self.children)

    @staticmethod
    def value(node):
        if not node.children:
            return sum(node.data_vals)
        return sum(Node.value(node.children[data_val - 1]) for data_val in node.data_vals if data_val < len(node.children) + 1)

def read_file():
    with open(input_filename) as f:
        return [int(i) for i in f.read().split(' ')]

def setup():
    nums = read_file()
    base = Node(0, nums[0], nums[1])
    total = 0
    ind = 0
    stack = [base]
    while stack:
        top = stack[-1]
        if top.child_remaining == 0:
            stack.pop()
            top.data_vals = nums[(ind + 2):(ind + top.data_len + 2)]
            ind += top.data_len
        else:
            ind += 2
            next = Node(ind, nums[ind], nums[ind + 1])
            stack.append(next)
            top.child_remaining -= 1
            top.children.append(next)
    return base

def part1(tree):
    return tree.metadata_sum()

def part2(tree):
    return Node.value(tree)

def main():
    start_setup = time.time()
    base = setup()
    end_setup = time.time()

    start_part1 = time.time()
    res_part1 = part1(base)
    end_part1 = time.time()

    start_part2= time.time()
    res_part2 = part2(base)
    end_part2 = time.time()

    print(f"part 1: {res_part1}")
    print(f"part 2: {res_part2}")
    print(f"setup took {end_setup - start_setup} seconds")
    print(f"part 1 took {end_part1 - start_part1} seconds")
    print(f"part 2 took {end_part2 - start_part2} seconds")
    print(f"overall took {end_part2 - start_setup} seconds")

if __name__ == '__main__':
    main()

#!/usr/local/bin/python3

import time
from parse import parse
from itertools import cycle
from collections import deque

input_filename = "../input/input_day9.txt"

def setup():
    with open(input_filename) as f:
        for line in f.read().splitlines():
            players, last = parse("{:d} players; last marble is worth {:d} points", line)
    return players, last

def play_game(players, last):
    board = deque([0])
    scores = {i:0 for i in range(players)}
    for player, marble in zip(cycle(range(players)), range(1, last + 1)):
        if marble % 23:
            board.rotate(-2)
            board.appendleft(marble)
        else:
            board.rotate(7)
            val = board.popleft()
            scores[player] += marble
            scores[player] += val
    return max(scores.items(), key=lambda s: s[1])

def part1(players, last):
    return play_game(players, last)

def part2(players, last):
    return play_game(players, last * 100)

def main():
    start_setup = time.time()
    players, last = setup()
    end_setup = time.time()

    start_part1 = time.time()
    res_part1 = part1(players, last)
    end_part1 = time.time()

    start_part2= time.time()
    res_part2 = part2(players, last)
    end_part2 = time.time()

    print(f"part 1: {res_part1}")
    print(f"part 2: {res_part2}")
    print(f"setup took {end_setup - start_setup} seconds")
    print(f"part 1 took {end_part1 - start_part1} seconds")
    print(f"part 2 took {end_part2 - start_part2} seconds")
    print(f"overall took {end_part2 - start_setup} seconds")

if __name__ == '__main__':
    main()

