#!/usr/local/bin/python3

import time
from collections import Counter, defaultdict

input_filename = "../../input/input_day13.txt"

class Cart:
    def __init__(self, x, y, direction):
        self.x = x
        self.y = y
        self.direction = direction
        self.turn = 0
        self.crashed = False

    def __repr__(self):
        return f"Cart({self.x}, {self.y}, {self.direction}, {self.turn})"

class System:
    def __init__(self, carts, tracks):
        self.carts = carts
        self.tracks = tracks
        self.turns = 0
        self.max_x = max(self.tracks, key=lambda xy: xy[0])[0]
        self.max_y = max(self.tracks, key=lambda xy: xy[1])[1]

    def print_board(self):
        tracks = [[self.tracks.get((x, y), ' ') for x in range(self.max_x + 1)] for y in range(self.max_y + 1)]
        for cart in self.carts:
            x, y = cart.x, cart.y
            tracks[y][x] = cart.direction
        for row in tracks:
            print("".join(row))

    def process(self, first=True):
        self.turns += 1
        self.carts.sort(key=lambda c: c.x)
        self.carts.sort(key=lambda c: c.y)
        coords = defaultdict(list)
        coords.update(((cart.x, cart.y),[cart]) for cart in self.carts)

        for cart in self.carts:
            if not cart.crashed:
                x, y = cart.x, cart.y
                if len(coords[(x, y)]) > 1:
                    for crashed in coords[(x, y)]:
                        crashed.crashed = True
                    if first:
                        return x, y
                else:
                    coords[(x, y)].remove(cart)

                    if cart.direction == '^':
                        y -= 1
                    elif cart.direction == 'v':
                        y += 1
                    elif cart.direction == '>':
                        x += 1
                    else:
                        x -= 1

                    cart.x, cart.y = x, y
                    coords[(x, y)].append(cart)

                    if first and len(coords[(x, y)]) > 1:
                        for crashed in coords[(x, y)]:
                            crashed.crashed = True
                        if first:
                            return x, y

                    tile = self.tracks[(x, y)]
                    if tile == "/":
                        cart.direction = 'v^><'['<>^v'.find(cart.direction)]
                    if tile == "\\":
                        cart.direction = '^v<>'['<>^v'.find(cart.direction)]
                    if tile == "+":
                        cart.direction = '<^>v<^'['^>v<'.find(cart.direction) + cart.turn % 3]
                        cart.turn += 1

        self.carts = [cart for cart in self.carts if len(coords[(cart.x, cart.y)]) == 1]
        return None


def setup():
    carts = []
    world = {}
    with open(input_filename) as f:
        for y, row in enumerate(f):
            for x, tile in enumerate(row.rstrip()):
                if tile != ' ':
                    if tile in "<>^v":
                        carts.append(Cart(x, y, tile))
                        world[(x, y)] = '--||'['><v^'.find(tile)]
                    else:
                        world[(x, y)] = tile
    return System(carts, world)

def part1(system):
    run = system.process()
    while run is None:
        run = system.process()
    return run

def part2(system):
    while len(system.carts) > 1:
        system.process(False)
    if len(system.carts) == 1:
        cart = system.carts[0]
        return cart.x, cart.y

def main():
    start_setup = time.time()
    system1 = setup()
    system2 = setup()
    end_setup = time.time()

    start_part1 = time.time()
    res_part1 = part1(system1)
    end_part1 = time.time()

    start_part2 = time.time()
    res_part2 = part2(system2)
    end_part2 = time.time()

    print(f"part 1: {res_part1}")
    print(f"part 2: {res_part2}")
    print(f"setup took {end_setup - start_setup} seconds")
    print(f"part 1 took {end_part1 - start_part1} seconds")
    print(f"part 2 took {end_part2 - start_part2} seconds")
    print(f"overall took {end_part2 - start_setup} seconds")

if __name__ == '__main__':
    main()

from typing import NamedTuple
from dataclasses import dataclass
import enum
import itertools
import collections

class Pt(NamedTuple('Pt', [('x', int), ('y', int)])):
    def __add__(self, other):
        return type(self)(self.x + other.x, self.y + other.y)

    @property
    def nb4(self):
        return [self + d for d in [Pt(0, 1), Pt(1, 0), Pt(0, -1), Pt(-1, 0)]]

class Team(enum.Enum):
    ELF = enum.auto()
    GOBLIN = enum.auto()

@dataclass
class Unit:
    team: Team
    position: Pt
    hp: int = 200
    alive: bool = True
    power: int = 3

class ElfDied(Exception):
    pass

class Grid(dict):
    def __init__(self, lines, power=3):
        super().__init__()

        self.units = []

        for i, line in enumerate(lines):
            for j, el in enumerate(line):
                self[Pt(i, j)] = el == '#'

                if el in 'EG':
                    self.units.append(Unit(
                        team={'E': Team.ELF, 'G': Team.GOBLIN}[el],
                        position=Pt(i, j),
                        power={'E': power, 'G': 3}[el]
                    ))

    def play(self, elf_death=False):
        rounds = 0
        while True:
            if self.round(elf_death=elf_death):
                break
            rounds += 1
        return rounds * sum(unit.hp for unit in self.units if unit.alive)

    def round(self, elf_death=False):
        for unit in sorted(self.units, key=lambda unit: unit.position):
            if unit.alive:
                if self.move(unit, elf_death=elf_death):
                    return True

    def move(self, unit, elf_death=False):
        targets = [target for target in self.units if unit.team != target.team and target.alive]
        occupied = set(u2.position for u2 in self.units if u2.alive and unit != u2)

        if not targets:
            return True

        in_range = set(pt for target in targets for pt in target.position.nb4 if not self[pt] and pt not in occupied)

        if not unit.position in in_range:
            move = self.find_move(unit.position, in_range)

            if move:
                unit.position = move

        opponents = [target for target in targets if target.position in unit.position.nb4]

        if opponents:
            target = min(opponents, key=lambda unit: (unit.hp, unit.position))

            target.hp -= unit.power

            if target.hp <= 0:
                target.alive = False
                if elf_death and target.team == Team.ELF:
                    raise ElfDied()

    def find_move(self, position, targets):
        visiting = collections.deque([(position, 0)])
        meta = {position: (0, None)}
        seen = set()
        occupied = {unit.position for unit in self.units if unit.alive}

        while visiting:
            pos, dist = visiting.popleft()
            for nb in pos.nb4:
                if self[nb] or nb in occupied:
                    continue
                if nb not in meta or meta[nb] > (dist + 1, pos):
                    meta[nb] = (dist + 1, pos)
                if nb in seen:
                    continue
                if not any(nb == visit[0] for visit in visiting):
                    visiting.append((nb, dist + 1))
            seen.add(pos)

        try:
            min_dist, closest = min((dist, pos) for pos, (dist, parent) in meta.items() if pos in targets)
        except ValueError:
            return

        while meta[closest][0] > 1:
            closest = meta[closest][1]

        return closest

