def apply_rule(applying, part1=True):
    ins_list = [Addr, Addi, Mulr, Muli, Banr, Bani, Borr, Bori,
                Setr, Seti, Gtir, Gtri, Gtrr, Eqir, Eqri, Eqrr]
    applied = [(ins, ins(*applying.ins[1:]).apply_rule(applying.before[:])) for ins in ins_list]
    if part1:
        return len([res for ins, res in applied if res == applying.result])
    else:
        return [ins for ins, res in applied if res == applying.result]

def setup():
    with open(input_filename) as f:
        lines = f.read().splitlines()
        prev_space = False
        part1_ins = []
        part2_ins = []
        lines = iter(lines)
        while True:
            line = next(lines)
            if line == '':
                if prev_space:
                    next(lines)
                    for line in lines:
                        part2_ins.append(tuple(parse('{:d} {:d} {:d} {:d}', line)))
                    return part1_ins, part2_ins
                prev_space = True
            else:
                prev_space = False
                before = list(parse("Before: [{:d}, {:d}, {:d}, {:d}]", line))
                ins = tuple(parse("{:d} {:d} {:d} {:d}", next(lines)))
                after = list(parse("After:  [{:d}, {:d}, {:d}, {:d}]", next(lines)))
                part1_ins.append(InsChange(before, ins, after))
        return part1, part2

def part1(ins_list):
    total = 0
    for ins in ins_list:
        if apply_rule(ins) >= 3:
            total += 1
    return total

def part2(ins_list, actual_data):
    opcodes = {}
    for ins in ins_list:
        res = apply_rule(ins, False)
        if ins.ins[0] in opcodes:
            opcodes[ins.ins[0]] = opcodes[ins.ins[0]] & {r for r in res}
        else:
            opcodes[ins.ins[0]] = {r for r in res}

    actual = {}
    while len(actual) < 16:
        for k, v in opcodes.items():
            if len(v) == 1:
                ins = v.pop()
                actual[k] = ins
                for code in opcodes:
                    if ins in opcodes[code]:
                        opcodes[code].remove(ins)

    opcodes = actual
    state = [0, 0, 0, 0]
    for ins in actual_data:
        apply = opcodes[ins[0]](*ins[1:])
        apply.apply_rule(state)
    return state[0]

def main():
    start_setup = time.time()
    ins1, ins2 = setup()
    end_setup = time.time()

    start_part1 = time.time()
    res_part1 = part1(ins1)
    end_part1 = time.time()

    start_part2 = time.time()
    res_part2 = part2(ins1, ins2)
    end_part2 = time.time()

    print(f"part 1: {res_part1}")
    print(f"part 2: {res_part2}")
    print(f"setup took {end_setup - start_setup} seconds")
    print(f"part 1 took {end_part1 - start_part1} seconds")
    print(f"part 2 took {end_part2 - start_part2} seconds")
    print(f"overall took {end_part2 - start_setup} seconds")

if __name__ == '__main__':
    main()

#include <cstdio>
#include <cstdlib>
#include <string>
#include <vector>
#include <iostream>
#include <climits>

static constexpr int SPRING_X = 500, SPRING_Y = 0;

enum Element { SAND, CLAY, WATER, FLOW, VOID };

struct Vein {
	int x0, x1, y0, y1;

	// Default to a degenerate bounding box
	Vein() : x0(INT_MAX), x1(INT_MIN), y0(INT_MAX), y1(INT_MIN) {
	}

	Vein(const std::string &s) {
		char c;
		sscanf(s.c_str(), "%c=%d, %*c=%d..%d", &c, &x0, &y0, &y1);

		// Convert to half-open intervals: [x0,x1) [y0,y1)
		x1 = x0 + 1;
		y1++;

		if (c == 'y') {
			std::swap(x0, y0);
			std::swap(x1, y1);
		}
	}

	void envelop(const Vein &o) {
		x0 = std::min(x0, o.x0 - 1); // margin left
		x1 = std::max(x1, o.x1 + 1); // margin right
		y0 = std::min(y0, o.y0 - 1); // margin top
		y1 = std::max(y1, o.y1);
	}

	void rebase(const Vein &bbox) {
		x0 -= bbox.x0;
		x1 -= bbox.x0;
		y0 -= bbox.y0;
		y1 -= bbox.y0;
	}
};

class Map {
    private:
	int dim_x, dim_y;
	std::vector< std::vector<Element> > E;

    public:
	Map(int dim_x, int dim_y) : dim_x(dim_x), dim_y(dim_y) {
		for (int x = 0; x < dim_x; x++) {
			E.emplace_back(dim_y);
		}
	}

	void add_vein(Vein v) {
		for (int x = v.x0; x < v.x1; x++) {
			for (int y = v.y0; y < v.y1; y++) {
				set(x, y, CLAY);
			}
		}
	}

	bool in_bounds(int x, int y) const {
		return (x >= 0) && (x < dim_x) &&
		       (y >= 0) && (y < dim_y);
	}

	Element at(int x, int y) const {
		return in_bounds(x, y) ? E[x][y] : VOID;
	}

	void set(int x, int y, Element e) {
		if (in_bounds(x, y)) {
			E[x][y] = e;
		}
	}

	void out() const {
		for (int y = 1; y < dim_y; y++) {
			for (int x = 0; x < dim_x; x++) {
				putchar(".#~|"[at(x, y)]);
			}
			putchar('\n');
		}
	}

	int answer(bool part2) const {
		int ans = 0;
		for (int x = 0; x < dim_x; x++) {
			for (int y = 1; y < dim_y; y++) {
				auto e = at(x, y);
				if (e == WATER || (!part2 && e == FLOW)) {
					ans++;
				}
			}
		}
		return ans;
	}
};

static void fill(Map &M, int x, int y, int dir) {
	if (M.at(x, y) == FLOW) {
		fill(M, x + dir, y, dir);
		M.set(x, y, WATER);
	}
}

static bool flow(Map &M, int x, int y, int dir = 0) {
	auto e = M.at(x, y);
	if (e != SAND) {
		return (e != CLAY) && (e != WATER);
	}

	M.set(x, y, FLOW);

	// Try to flow down
	bool leaky = flow(M, x, y + 1, 0);
	if (leaky) {
		return true;
	}

	// Down is not leaky, flow laterally
	leaky  = (dir <= 0) && flow(M, x - 1, y, -1);
	leaky |= (dir >= 0) && flow(M, x + 1, y,  1);
	if (leaky) {
		return true;
	}

	if (dir == 0) {
		// Entire layer is watertight, fill it up
		fill(M, x,     y, -1);
		fill(M, x + 1, y,  1);
	}

	return false;
}

int main(int argc, char **argv) {
	std::istream *in = &std::cin;

	// Parse the input into a vector of veins
	std::vector<Vein> V;
	std::string line;
	while (getline(*in, line)) {
		V.push_back(line);
	}

	// Get bounding box
	Vein bbox; // The main one, if you will
	for (auto&& v : V) {
		bbox.envelop(v);
	}

	// Convert all veins to 0,0 array base
	for (auto& v : V) {
		v.rebase(bbox);
	}

	// Initialize the map
	Map M(bbox.x1 - bbox.x0, bbox.y1 - bbox.y0);
	for (auto&& v : V) {
		M.add_vein(v);
	}

	// Spring forth
	flow(M, SPRING_X - bbox.x0, std::max(0, SPRING_Y - bbox.y0));

#ifdef VERBOSE
	M.out();
#endif

	printf("Part 1: %d\n", M.answer(false));
	printf("Part 2: %d\n", M.answer(true));

	return EXIT_SUCCESS;
}

