    NARROW = 2

class Tool(enum.Enum):
    CLIMBING_GEAR = enum.auto()
    TORCH = enum.auto()
    NEITHER = enum.auto()

    def usable(self, region):
        return region in {
            Tool.CLIMBING_GEAR: {Region.ROCKY, Region.WET},
            Tool.TORCH: {Region.ROCKY, Region.NARROW},
            Tool.NEITHER: {Region.WET, Region.NARROW},
        }[self]

