        if x == 0 or y == 0:
            geologic_index[x, y] = 16807 * x + 48271 * y
        elif (x, y) == target:
            geologic_index[x, y] = 0
        else:
            geologic_index[x, y] = erosion_level[x-1,y] * erosion_level[x,y-1]

