            for idx, df in enumerate(immune):
                if idx in if_tgs:
                    continue
                tc = (calc_dmg(ak, df), df[-1], df[-2], idx)
                if tc > best_choice:
                    best_choice = tc
            if_tgs.append(best_choice[3])

        all_units = []
