            all_units.append([0, i, v])
        for i,v in enumerate(infect):
            all_units.append([1, i, v])

        all_units.sort(key=lambda v : -v[2][-2])

        alive_immune = immune[:]
        alive_infect = infect[:]

        total_deathtoll = 0

        for unit in all_units:
            if unit[0] == 0:
                if unit[2] not in alive_immune:
