                total_deathtoll += death_toll
                if immune[if_tgs[unit[1]]][0] <= 0:
                    alive_immune.remove(immune[if_tgs[unit[1]]])

        ## Stalemate
        if total_deathtoll == 0:
            return False

        immune = alive_immune
        infect = alive_infect

    return tuple(map(lambda w : sum(v[0] for v in w), [infect,immune]))

def dcopy(m):
