  prev = test[0]
  count = 1
  counts = []
  for c in test[1:]:
    if c == prev:
      count+=1
    else:
      counts.append(count)
      count = 1
    if int(c) < int(prev):
      return (False, False)
    prev = c
  counts.append(count)
  return (max(counts) >= 2, 2 in counts)

