object Day4 extends App {
  val input = Source.fromFile("day4")
  val PATTERN = """(\w+):(\S+)""".r
  val HEIGHT = """(\d+)(cm|in)""".r
  val color = """#[0-9Aa-f]{6}"""
  val pid = """\d{9}"""

