    height match {
      case HEIGHT(number,unit) =>
        val height = number.toInt
        unit match {
          case "in" => height >= 59 && height <= 76
          case "cm" => height >= 150 && height <= 193
        }
      case _ => false
    }
  }

  def enoughFields(entry:List[(String,String)]) = entry.length == 8 || (entry.length == 7 && !entry.exists(_._1 == "cid"))
  def valid(entry:(String,String)) = {
    val (key,valueTxt) = (entry._1,entry._2)
    lazy val value = entry._2.toInt
    key match {
      case "byr" => value >= 1920 && value <= 2002
      case "iyr" => value >= 2010 && value <= 2020
      case "eyr" => value >= 2020 && value <= 2030
      case "hgt" => validHeight(valueTxt)
      case "hcl" => valueTxt.matches(color)
      case "ecl" => List("amb","blu","brn","gry","grn","hzl","oth").contains(valueTxt)
      case "pid" => valueTxt.matches(pid)
      case _ => true
    }
  }

  println("Part 1:" + data.count(enoughFields))
  println("Part 2:" + data.count ( entry => entry.forall(valid) && enoughFields(entry)))
}

