        for (auto elem : inputs)
        {
            int32_t row = 0;
            int32_t seat = 0;

            for (int index = 0; index < 7; ++index)
            {
                if (elem[index] == 'B')
                    row |= 0x1 << (6 - index);
            }

            for (int index = 7; index < 10; ++index)
            {
                if (elem[index] == 'R')
                    seat |= 0x1 << (9 - index);
            }

            int32_t seatId = row * 8 + seat;
            seatIds.push_back(seatId);
        }

        std::sort(seatIds.begin(), seatIds.end());
    }

