def bootcode(lines):
    acc, idx, seen = 0, 0, set()
    while True:
        if idx in seen:
            return False, acc
        l = lines[idx].strip().split()
        instruction, value = l[0], int(l[1])
        seen.add(idx)
        acc += value if instruction == 'acc' else 0
        idx += value if instruction == 'jmp' else 1
        if idx >= len(lines):
            return True, acc


