def resolve(inst):
    visited = set()
    ind = 0
    acc = 0

    while ind < len(inst):
        if ind in visited:
            return False, acc
        visited.add(ind)
        curr, val = inst[ind].split()
        if curr == "jmp":
            ind += int(val)
        else:
            if curr == "acc":
                acc += int(val)
            ind += 1

    return True, acc


