State = namedtuple('State', ['pc', 'acc', 'pcs'])
Line = namedtuple('Line', ['cmd', 'arg'])

def next_st(code, st):
    commands = {
        'nop': lambda _, st: State(st.pc+1,st.acc,  st.pcs|{st.pc}),
        'acc': lambda x, st: State(st.pc+1,st.acc+x,st.pcs|{st.pc}),
        'jmp': lambda x, st: State(st.pc+x,st.acc,  st.pcs|{st.pc})}
    return commands[code[st.pc].cmd](code[st.pc].arg, st)

def loop_cond(st):
    return st.pc in st.pcs

def stop_cond(code, st):
    return loop_cond(st) or not (0 <= st.pc < len(code))

def run(code):
    return reduce(lambda _,st: st,
                  takewhile(lambda st: not stop_cond(code, st),
                            accumulate(count(),
                                       lambda st, _: next_st(code, st),
                                       initial=State(0, 0, set()))))
def subst_and_run(code):
    subst = {'nop': 'jmp', 'jmp': 'nop', 'acc': 'acc'}
    return next(
        dropwhile(lambda st: loop_cond(st),
                  accumulate((code[:i]+[Line(subst[l.cmd],l.arg)]+code[i+1:]
                              for i,l in enumerate(code)),
                             lambda _, mc: next_st(mc, run(mc)),
                             initial=State(0, 0, {0}))))

