def filter_loop(arr, col,str):
    if (np.shape(arr)[0] == 1):
        return arr
    else:
        inv = invert(arr) # invert array so stats.mode works as intended
        filter = np.empty([0,12])
        if str=="ox":
            value = stats.mode(inv[:,col])[0][0] 
            #calculate mode of column, keeping smallest mode (which is actually largest because we inverted)
        if str=="scrub":
            value = 1 - stats.mode(inv[:,col])[0][0] 
            #calculate mode of column, keeping smallest mode (which is largest because we inverted), then reverse the bit so we keep the anti-mode
        for data in inv:
            if data[col] == value:
                filter = np.row_stack((filter,data))
        return invert(filter) #revert before returning

