def gcd(a,b):
  if a*b == 0:
    return a+b
  return gcd(b, a%b)

def points_on_line(vent):
  if is_horiz_vert(vent):
    return(points_on_hv_line(vent))
  [(x0, y0), (x1,y1)]  = vent
  rise = y1 - y0
  run = x1 - x0
  slope_gcd = gcd(abs(rise), abs(run))
  rise = rise // slope_gcd
  run = run // slope_gcd
  return [(x0+i*run, y0+i*rise) for i in range(((x1-x0)//run)+1)]

