# Part 2
# Off-by-one is a bitch, so take these recursion formulae with a fistful of salt
# P(i, d) = | 1 if i >= d
#           | else P(0, d-1)
#
# P(0, d) = | 1 if 0 >= d
#           | else P(6, d-1) + P(8, d-1)
#
# P(6, d-1) + P(8, d-1) = | 1 + P(8, d-1)  if 6 >= d-1
#                         | else  P(6, d-8) + P(8, d-1) + P(8, d-8)
#
# etc. for roof((d-1)/7) child families
cache = {}
def size_of_family(initial_state, days_to_go):
    if initial_state > 0:
        return size_of_family(0, days_to_go - initial_state)
    if days_to_go <= 0:
        return 1
    if days_to_go not in cache:
        cache[days_to_go] = 1 + sum(
            size_of_family(8, days_to_go - 1 - 7 * generation)
            for generation in range((days_to_go - 1) // 7 + 1)
        )
    return cache[days_to_go]


def smart_spawn(lanternfish_timers, days_to_go):
    return sum(size_of_family(fish, days_to_go) for fish in lanternfish_timers)


