        # part 2
        self.us = self.pick_rps()

    def score_points(self):
        score = self.us.value + 1
        if self.us > self.them:
            score += 6
        elif self.us == self.them:
            score += 3
        return score

    def pick_rps(self):
        match self.inputs[1]:
            case "X":
                return RockPaperScissors((self.them.value - 1) % 3)
            case "Y":
                return RockPaperScissors(self.them.value)
            case "Z":
                return RockPaperScissors((self.them.value + 1) % 3)


