class RockPaperScissor:

    points_lose = 0
    points_draw = 3
    points_win = 6

    def __init__(self, choice) -> None:
        if choice in ["A", "X", "Rock"]:
            self.choice = "Rock"
            self.points = 1
        elif choice in ["B", "Y", "Paper"]:
            self.choice = "Paper"
            self.points = 2
        elif choice in ["C", "Z", "Scissors"]:
            self.choice = "Scissors"
            self.points = 3

    def __repr__(self) -> str:
        return f"<{self.choice} ({self.points})>"

    def fight(self, other) -> int:
        if self.choice == other.choice:
            return self.points + self.points_draw
        elif self.choice == "Rock" and other.choice == "Paper":
            return self.points + self.points_lose
        elif self.choice == "Paper" and other.choice == "Scissors":
            return self.points + self.points_lose
        elif self.choice == "Scissors" and other.choice == "Rock":
            return self.points + self.points_lose
        else:
            return self.points + self.points_win

    def _draw(self):
        return RockPaperScissor(self.choice)

    def _lose(self):
        if self.choice == 'Rock':
            return RockPaperScissor("Scissors")
        elif self.choice == 'Paper':
            return RockPaperScissor("Rock")
        elif self.choice == 'Scissors':
            return RockPaperScissor("Paper")

    def _win(self):
        if self.choice == 'Rock':
            return RockPaperScissor("Paper")
        elif self.choice == 'Paper':
            return RockPaperScissor("Scissors")
        elif self.choice == 'Scissors':
            return RockPaperScissor("Rock")

    def make_choice(self, outcome):
        if outcome == 'X':
            return self._lose()
        elif outcome == 'Y':
            return self._draw()
        else:
            return self._win()


