class Monkey:
    def __init__(self, monkey_do, worry_divider):
        monkey_stats = monkey_do.splitlines()
        self.items = eval('[' + monkey_stats[1][18:] + ']')
        self.operation = eval('lambda old: ' + monkey_stats[2][19:])
        self.test = int(monkey_stats[3][21:])
        self.iftrue = int(monkey_stats[4][29:])
        self.iffalse = int(monkey_stats[5][30:])
        self.inspect_count = 0
        self.worry_divider = worry_divider

    def play(self):
        while self.items:
            self.inspect_count += 1
            worry = self.operation(self.items.pop(0)) // self.worry_divider
            if worry % self.test:
                yield self.iffalse, worry % 9699690 if self.worry_divider == 1 else worry
            else:
                yield self.iftrue, worry

