def rec_lt(a, b):
    if type(a) == int and type(b) == list:
        return rec_lt([a], b)
    if type(a) == list and type(b) == int:
        return rec_lt(a, [b])
    if type(a) == list and type(b) == list:
        for l, r in zip(a, b):
            x = rec_lt(l, r)
            if x is not None:
                return x
        return rec_lt(len(a), len(b))
    if a == b:
        return None
    return a < b


