def get_winning_times(d, t):
    x1 = math.floor((d - math.sqrt(d ** 2 - 4 * t)) / 2) + 1
    x2 = math.ceil((d + math.sqrt(d ** 2 - 4 * t)) / 2) - 1
    return x2 - x1 + 1

