def dfs( m, r, n, ri, ni, w ):
    if ( ri, ni, w ) in m:
        return m[ ( ri, ni, w ) ]
    if ri == len( r ):
        return ( ( ni == len( n ) and w == 0 ) or
                 ( ni == len( n ) - 1 and w == n[ ni ] ) )
    t = 0
    if r[ ri ] in ".?":
        if w == 0:
            t += dfs( m, r, n, ri + 1, ni, 0 )
        elif n[ ni ] == w:
            t += dfs( m, r, n, ri + 1, ni + 1, 0 )
    if r[ ri ] in "#?" and ni < len( n ) and w < n[ ni ]:
            t += dfs( m, r, n, ri + 1, ni, w + 1 )
    m[ ( ri, ni, w ) ] = t
    return t

