from collections import Counter


def main() -> None:
    l1, l2 = read_input()
    print(f"Part 1: {compute_total_distance(l1, l2)}")
    print(f"Part 2: {similarity_score(l1, l2)}")


def compute_total_distance(left_list: list[int], right_list: list[int]) -> int:
    left_list.sort()
    right_list.sort()
    total = 0
    for left, right in zip(left_list, right_list):
        total += abs(left - right)
    return total


def similarity_score(left_list: list[int], right_list: list[int]) -> int:
    counts = Counter(right_list)
    def helper(n: int, counter=counts) -> int:
        return n * counter.get(n, 0)
    return sum(map(helper, left_list))


def read_input() -> tuple[list[int], list[int]]:
    left_list = []
    right_list = []
    with open("./input/day01.txt") as file:
        for line in file.readlines():
            left, right = line.split()
            left_list.append(int(left))
            right_list.append(int(right))
    return left_list, right_list

