def is_safe(record):
    pos_count = 0
    neg_count = 0

    for i in range(1, len(record)):
        diff = abs(record[i] - record[i - 1])
        if 1 <= diff <= 3:
            if record[i] > record[i - 1]:
                pos_count += 1
            else:
                neg_count += 1
        else:
            return False

    return not (pos_count > 0 and neg_count > 0)


def part1(data):
    safe_count = sum(1 for record in data if is_safe(record))
    print("Part 1:", safe_count)


def part2(data):
    safe_count = 0

    for record in data:
        if is_safe(record):
            safe_count += 1
        else:
            # Remove each element and check for SAFE
            for j in range(len(record)):
                modified_record = record[:j] + record[j + 1:]
                if is_safe(modified_record):
                    safe_count += 1
                    break

    print("Part 2:", safe_count)


