def neighbors(r, c, rows, cols):
    for nr, nc in [(r-1, c), (r+1, c), (r, c-1), (r, c+1)]:
        if 0 <= nr < rows and 0 <= nc < cols:
            yield nr, nc

def pt1(map_data, start_r, start_c):
    rows, cols = len(map_data), len(map_data[0])
    seen = {(start_r, start_c)}
    q = [(start_r, start_c)]
    nines = 0

    while q:
        r, c = q.pop(0)
        h = map_data[r][c]
        if h == 9:
            nines += 1
            continue
        nh = h + 1
        for nr, nc in neighbors(r, c, rows, cols):
            if (nr, nc) not in seen and map_data[nr][nc] == nh:
                seen.add((nr, nc))
                q.append((nr, nc))

    return nines

def pt2(r, c, mp, ways):
    if ways[r][c] is not None:
        return ways[r][c]
    h = mp[r][c]
    if h == 9:
        ways[r][c] = 1
        return 1

    rows, cols = len(mp), len(mp[0])
    nh = h + 1
    total = 0
    for nr, nc in neighbors(r, c, rows, cols):
        if mp[nr][nc] == nh:
            total += pt2(nr, nc, mp, ways)

    ways[r][c] = total
    return total

