def blink(stone, blinks, memo):
    if blinks == 75:
        return 1

    this_memo_entry = stone + "." + str(blinks)
    if this_memo_entry in memo:
        return memo[this_memo_entry]

    if stone == '0':
        memo[this_memo_entry] = blink('1', blinks+1, memo)
