MASK = (1 << 24) - 1 # 0xffffff
@njit
def randomize(seed):
    seed = (seed ^ (seed << 6)) & MASK
    seed = (seed ^ (seed >> 5)) & MASK
    return (seed ^ (seed << 11)) & MASK

def part2(seeds):
    m = defaultdict(int)
    for s in seeds:
        seen = set()
        prices = [p%10 for p in s]
        deltas = [b-a for a,b in pairwise(prices)]
        for i,q in enumerate(quadwise(deltas),start=4):
            if q not in seen:
                m[q]+=prices[i]
                seen.add(q)
    return max(m.values())

